(10, 'Water & Sanitation', 'The Water and Sanitation Department is responsible for the planning, design, and management of water supply, treatment, and distribution systems, as well as sanitation and wastewater infrastructure. The department oversees stormwater management, drainage systems, watershed protection, faecal sludge collection and treatment, latrines, and landfill engineering to ensure public health, environmental protection, and sustainable water resource management.', 'WS', 'Headquarters - Floor 3', 500000.00, '0788988268', 'shemapd2@gmail.com', 'https://github.com/shemagithub', 'active', 'Water & Sanitation –', '2025-12-22 20:22:55', '2025-12-22 20:33:26'),
(11, 'Energy ', 'The Energy Department focuses on the design, development, and implementation of energy systems and infrastructure. Its responsibilities include renewable and conventional energy systems, energy transfer and distribution, hydropower and geothermal systems, pipeline engineering, and energy efficiency solutions aimed at supporting sustainable industrial, agricultural, and community development', 'EA', 'Headquarters - Floor 3', 5000000.00, '0788988268', 'shemapd2@gmail.com', 'https://github.com/shemagithub', 'active', 'hghggghjhjhjhj', '2025-12-22 20:26:00', '2025-12-22 20:33:56'),
(12, 'Infrastructure', 'The Infrastructure Department is responsible for the planning, design, and supervision of major infrastructure projects, including roads, bridges, tunnels, railways, and urban utilities. The department ensures resilient, safe, and sustainable infrastructure development through multidisciplinary engineering coordination, construction administration, and quality control', 'IED', 'Headquarters - Floor 2', 5000000.00, '0788988268', 'shemapd2@gmail.com', 'https://github.com/shemagithub', 'active', 'frdfgdfgfh', '2025-12-22 20:26:51', '2025-12-22 20:34:44'),
(13, 'Lead Design & General Planning', 'The Lead Design and General Planning Department coordinates multidisciplinary design activities and provides overall project planning and technical leadership. It is responsible for concept development, master planning, feasibility studies, GIS-based planning, modeling and simulation, and ensuring design integration, compliance, and quality across all engineering disciplines.', 'BHSD', 'Branch Office - Downtown', 5000000.00, '0788988268', 'shemapd2@gmail.com', 'https://github.com/shemagithub', 'active', 'Business, Health & Social Development', '2025-12-22 20:27:36', '2025-12-22 20:35:22'),
(14, 'Structural Design', 'The Structural Design Department specializes in the analysis and design of structural systems for buildings and infrastructure projects. It delivers safe, efficient, and code-compliant structural solutions, including foundations, concrete and steel structures, bridges, and geotechnical considerations, ensuring structural integrity and long-term performance.', 'SD', 'Headquarters - Floor 2', 5000000.00, '0788988268', 'shemapd2@gmail.com', 'https://github.com/shemagithub', 'active', 'hgjgfghhdf', '2025-12-22 20:40:10', '2025-12-22 20:40:10'),
(15, 'Building Services & Urban development', 'The Building Services Department designs and manages mechanical, electrical, and plumbing (MEP) systems for buildings and facilities. Its scope includes HVAC, electrical power, lighting, fire protection, water supply, drainage, and energy-efficient building systems to ensure functionality, safety, comfort, and sustainability.', 'BS', 'Headquarters - Floor 2', NULL, '0788988268', 'shemapd2@gmail.com', 'https://github.com/shemagithub', 'active', 'gghghfhyt', '2025-12-22 20:41:07', '2026-06-22 13:42:31'),
(16, 'Engineering', 'Engineering Department', 'ENG', '', NULL, NULL, NULL, NULL, 'active', NULL, '2026-01-13 11:56:13', '2026-01-13 11:56:13'),
(19, 'Administration', 'Administration & Front Office', 'ADM', '', NULL, NULL, NULL, NULL, 'active', NULL, '2026-06-13 14:34:33', '2026-06-13 14:34:33'),
(20, 'Finance', 'Financial planning and accounting', 'FIN-001', 'Head Office', 0.00, NULL, 'finance@company.com', NULL, 'active', 'Auto-created by init-staff script', '2026-06-23 02:30:28', '2026-06-23 02:30:28');

