--
-- Table structure for table `projects`
--

CREATE TABLE `projects` (
  `id` int(11) NOT NULL,
  `project_id` varchar(50) DEFAULT NULL COMMENT 'Unique project identifier (e.g., PRJ-2024-001)',
  `name` varchar(500) DEFAULT NULL COMMENT 'Project name/title',
  `client` varchar(255) DEFAULT NULL COMMENT 'Client name',
  `department` varchar(255) DEFAULT NULL COMMENT 'Department assigned to project',
  `manager` varchar(255) DEFAULT NULL COMMENT 'Project manager name',
  `status` enum('planning','ongoing','near_completion','completed','overdue','on_hold','cancelled') DEFAULT NULL COMMENT 'Current project status',
  `start_date` date DEFAULT NULL COMMENT 'Project start date',
  `end_date` date DEFAULT NULL COMMENT 'Project end date',
  `progress` int(11) DEFAULT NULL COMMENT 'Project completion percentage (0-100)',
  `budget` decimal(15,2) DEFAULT NULL COMMENT 'Total project budget',
  `spent` decimal(15,2) DEFAULT NULL COMMENT 'Amount spent so far',
  `team_size` int(11) DEFAULT NULL COMMENT 'Number of team members assigned',
  `priority` enum('low','medium','high','critical') DEFAULT NULL COMMENT 'Project priority level',
  `description` text DEFAULT NULL COMMENT 'Project description/details',
  `location` varchar(255) DEFAULT NULL COMMENT 'Project location',
  `assigned_to` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

